            disabled={direct3dLevelOptions.length < 2}
            className="grid size-6 place-items-center rounded border border-border bg-surface text-xs text-muted disabled:opacity-40"
            onClick={() => stepAuthoringWorkPlaneLevel(-1)}
          >
            ^

