// ── OSM site context: fetch neighbouring buildings/roads/trees from Overpass API ──
useEffect(() => {
  const root = rootGroupRef.current;

  function removePrevious() {
    const prev = osmContextGroupRef.current;
    if (prev) {
      prev.parent?.remove(prev);
      disposeObject3D(prev);
      osmContextGroupRef.current = null;
    }
  }

  if (!root || !georeference) {
    removePrevious();
    return;
  }

  let cancelled = false;

  fetchOsmContext(georeference.anchorLat, georeference.anchorLon, georeference.contextRadiusM)
    .then((features) => {
      if (cancelled) return;
      removePrevious();
      const group = makeOsmContextGroup(features, osmHiddenLayers);
      // Insert before BIM geometry so house elements draw on top.
      root.children.unshift(group);
      root.add(group);
      osmContextGroupRef.current = group;
    })
    .catch((err: unknown) => {
      if (!cancelled) console.warn('[OSM] fetch failed:', err);
    });

  return () => {
    cancelled = true;
  };
}, [georeference, osmHiddenLayers]);

// ── F-011: visual style (shaded / wireframe / colors / hidden / realistic / high fidelity / path trace) ──
useEffect(() => {
  const cache = bimPickMapRef.current;
  for (const [, obj] of cache) {
    obj.traverse((child) => {
      if (!(child instanceof THREE.Mesh)) return;

      if (viewerRenderStyle === 'wireframe') {
        // Restore original if we previously swapped it, then enable wireframe.
        if (child.userData.originalMaterial) {
          child.material = child.userData.originalMaterial as THREE.Material;

